<?php
 namespace WPAICG\Vector\Providers\OpenAI\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_OpenAI_Strategy; use WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder; use WP_Error; if (!defined('ABSPATH')) { exit; } function query_vectors_logic(AIPKit_Vector_OpenAI_Strategy $strategyInstance, string $index_name, array $query_vector, int $top_k, array $filter = []): array|WP_Error { if (!$strategyInstance->get_is_connected_status()) { return new WP_Error('not_connected', __('Not connected to OpenAI.', 'gpt3-ai-content-generator')); } $vector_store_id = $index_name; if (!isset($query_vector['query_text']) || !is_string($query_vector['query_text'])) { return new WP_Error('invalid_query_type', __('For OpenAI vector store search, query_vector must be an array containing a "query_text" string.', 'gpt3-ai-content-generator')); } $url_params = [ 'base_url' => $strategyInstance->get_base_url(), 'api_version' => $strategyInstance->get_api_version(), 'vector_store_id' => $vector_store_id ]; $url = OpenAIUrlBuilder::build('vector_stores_id_search', $url_params); if (is_wp_error($url)) return $url; $body = [ 'query' => $query_vector['query_text'], 'max_num_results' => max(1, min($top_k, 50)), ]; if (!empty($filter)) { $body['filters'] = $filter; } if (isset($query_vector['ranking_options'])) { $body['ranking_options'] = $query_vector['ranking_options']; } $response = _request_logic($strategyInstance, 'POST', $url, $body); if (is_wp_error($response)) return $response; $results = []; if (isset($response['data']) && is_array($response['data'])) { foreach ($response['data'] as $item) { $results[] = [ 'id' => $item['file_id'] ?? null, 'score' => $item['score'] ?? null, 'metadata' => $item['attributes'] ?? [], 'content' => $item['content'] ?? null, 'raw_item' => $item ]; } } return $results; }